    requiredTerms: ["Iran", "2027"],
    avoidTerms: ["related", "similar", "proxy", "other"],
    limit: 3,
  });

  const resolved = shortlisted[0] || candidates[0] || null;
  const conditionId = resolved?.conditionId || null;
  const slug = resolved?.slug || null;

  if (!conditionId && !slug) {
    return {
      stopReason: "Could not resolve a direct instrument for the requested market.",
      attemptedBranches: ["search_markets", "semantic_targeting"],
      missingData: ["conditionId", "slug"],
      marketQuery,
    };
  }

  // Batch independent read-only calls across different endpoints only after the exact market is resolved.
  const batch = await callMcpSkillsParallel({
    label: "iran-market-readonly-batch",
    calls: [
      {
        key: "whales",
        toolId,
        toolName: "analyze_top_holders",
        args: conditionId
          ? { conditionId, deepFetch: true, limit: 50 }
          : { slug, deepFetch: true, limit: 50 },
      },
      {
        key: "whaleFlow",
        toolId,
        toolName: "analyze_whale_flow",
        args: conditionId
          ? { conditionId, hoursBack: 24 }
          : { slug, hoursBack: 24 },
      },
      {
        key: "oiSnapshotA",
        toolId,
        toolName: "get_market_open_interest",
        args: { conditionId },
      },
      {
        key: "rules",
        toolId,
        toolName: "check_market_rules",
        args: conditionId
          ? { conditionId }
          : { slug },
      },
    ],
  });

  const whales = batch.results.find((r) => r.key === "whales");
  const whaleFlow = batch.results.find((r) => r.key === "whaleFlow");
  const oiSnapshotA = batch.results.find((r) => r.key === "oiSnapshotA");
  const rules = batch.results.find((r) => r.key === "rules");

  const whaleData = whales?.status === "fulfilled" ? whales.value : null;
  const whaleFlowData = whaleFlow?.status === "fulfilled" ? whaleFlow.value : null;
  const oiA = oiSnapshotA?.status === "fulfilled" ? oiSnapshotA.value : null;
  const rulesData = rules?.status === "fulfilled" ? rules.value : null;

  // Same-endpoint exploration must stay sequential, so take a second OI snapshot only after the first one.
  // This provides an actual delta for "how fast is open interest changing" instead of a single snapshot.
  await new Promise((resolve) => setTimeout(resolve, 1500));

  const oiSnapshotB = await callMcpSkill({
    toolId,
    toolName: "get_market_open_interest",
    args: { conditionId },
  });

  const oiRowsA = Array.isArray(oiA?.openInterest) ? oiA.openInterest : [];
  const oiRowsB = Array.isArray(oiSnapshotB?.openInterest) ? oiSnapshotB.openInterest : [];

  const oiValueA = oiRowsA.find((row) => row?.conditionId === conditionId)?.value ?? oiRowsA[0]?.value ?? null;
  const oiValueB = oiRowsB.find((row) => row?.conditionId === conditionId)?.value ?? oiRowsB[0]?.value ?? null;

  const fetchedAtA = oiA?.fetchedAt || null;
  const fetchedAtB = oiSnapshotB?.fetchedAt || null;

  const oiChangeRate =
    typeof oiValueA === "number" && typeof oiValueB === "number" && fetchedAtA && fetchedAtB
      ? {
          snapshotA: { value: oiValueA, fetchedAt: fetchedAtA },
          snapshotB: { value: oiValueB, fetchedAt: fetchedAtB },
          delta: oiValueB - oiValueA,
          direction: oiValueB > oiValueA ? "up" : oiValueB < oiValueA ? "down" : "flat",
        }
      : {
          missingData: ["openInterestSnapshotA", "openInterestSnapshotB"],
          stopReason: "Could not compute OI change rate from two usable snapshots.",
        };

  const currentPrice = typeof whaleFlowData?.selectedMarket?.currentPrice === "number"
    ? whaleFlowData.selectedMarket.currentPrice
    : null;

  const priceCents = currentPrice == null ? null : Math.round(currentPrice * 100);

  return {
    market: whaleFlowData?.selectedMarket?.title || resolved?.title || marketQuery,
    selection: {
      conditionId,
      slug,
      resolvedBy: discovery?.searchMethod || "search_markets + semantic_targeting",
    },
    currentPrice: currentPrice,
    currentPriceCents: priceCents,
    topHolderConcentration: whaleData?.concentration || whaleData?.marketConcentration || null,
    whaleFlow: whaleFlowData?.whaleFlow || whaleFlowData || null,
    smartMoneySignal: whaleFlowData?.holderAnalysis?.smartMoneySignal || whaleData?.smartMoneySignal || null,
    openInterest: {
      snapshotA: oiValueA,
      snapshotB: oiValueB,
      changeRate,
    },
    rules: rulesData || null,
    comparisonToCurrentPrice: {
      priceCents,
      flowAgreement:
        whaleFlowData?.holderAnalysis?.smartMoneySignal?.direction
          ? {
              direction: whaleFlowData.holderAnalysis.smartMoneySignal.direction,
              confidence: whaleFlowData.holderAnalysis.smartMoneySignal.confidence,
              reasoning: whaleFlowData.holderAnalysis.smartMoneySignal.reasoning,
            }
          : null,
    },
    dataQuality: {
      resolvedInstrument: Boolean(conditionId || slug),
      usedTwoOiSnapshots: typeof oiValueA === "number" && typeof oiValueB === "number",
      parallelBatchSucceeded: batch.summary,
    },
  };
}

