import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";
  const query = "Will the Fed decrease interest rates by 50+ bps after the April 2026 meeting?";

  const discoveryBatch = await callMcpSkillsParallel({
    label: "fed-rate-discovery",
    calls: [
      {
        key: "search-markets",
        toolId,
        toolName: "search_markets",
        args: { query, status: "live", limit: 10, category: "politics" }
      },
      {
        key: "top-markets",
        toolId,
        toolName: "get_top_markets",
        args: { limit: 15, sortBy: "volume", category: "politics", includeNearResolved: true }
      }
    ]
  });

  const searchMarkets =
    discoveryBatch.results.find((r) => r.key === "search-markets")?.status === "fulfilled"
      ? discoveryBatch.results.find((r) => r.key === "search-markets").value
      : null;

  const topMarkets =
    discoveryBatch.results.find((r) => r.key === "top-markets")?.status === "fulfilled"
      ? discoveryBatch.results.find((r) => r.key === "top-markets").value
      : null;

  const searchCandidates = Array.isArray(searchMarkets?.results) ? searchMarkets.results : [];
  const topCandidates = Array.isArray(topMarkets?.markets) ? topMarkets.markets : [];

  const shortlist = [
    ...searchCandidates.map((m) => ({
      ...m,
      source: "search_markets"
    })),
    ...topCandidates.map((m) => ({
      ...m,
      source: "get_top_markets"
    }))
  ];

  const ranked = pickTopSemanticCandidates({
    target: "the exact live Fed market asking whether rates decrease by 50+ bps after the April 2026 meeting",
    candidates: shortlist,
    requiredTerms: ["Fed", "April 2026", "50", "bps"],
    avoidTerms: ["non-fed", "crypto", "sports"],
    limit: 3
  });

  const chosen = ranked[0] || null;
  if (!chosen) {
    return {
      missingData: "No credible candidate market found in discovery results",
      attemptedBranches: ["search_markets", "get_top_markets"],
      stopReason: "shortlist_empty",
      discoveryBatch: discoveryBatch.summary
    };
  }

  const targetConditionId = chosen.conditionId || chosen.id || null;
  const targetSlug = chosen.slug || null;
  if (!targetConditionId && !targetSlug) {
    return {
      missingData: "Discovered candidate lacks both conditionId and slug",
      attemptedBranches: ["search_markets", "get_top_markets"],
      stopReason: "missing_target_identifier",
      chosenCandidate: {
        title: chosen.title,
        url: chosen.url,
        source: chosen.source
      }
    };
  }

  const analysisBatch = await callMcpSkillsParallel({
    label: "fed-market-analysis",
    calls: [
      {
        key: "efficiency",
        toolId,
        toolName: "check_market_efficiency",
        args: targetConditionId
          ? { conditionId: targetConditionId }
          : { slug: targetSlug }
      },
      {
        key: "liquidity",
        toolId,
        toolName: "analyze_market_liquidity",
        args: targetConditionId
          ? { conditionId: targetConditionId }
          : { slug: targetSlug }
      },
      {
        key: "related",
        toolId,
        toolName: "compare_market_against_related_contracts",
        args: {
          conditionId: targetConditionId || undefined,
          slug: targetSlug || undefined,
          query
        }
      },
      {
        key: "correlated",
        toolId,
        toolName: "find_correlated_markets",
        args: targetConditionId
          ? { conditionId: targetConditionId }
          : { slug: targetSlug }
      }
    ]
  });

  const efficiency =
    analysisBatch.results.find((r) => r.key === "efficiency")?.status === "fulfilled"
      ? analysisBatch.results.find((r) => r.key === "efficiency").value
      : null;

  const liquidity =
    analysisBatch.results.find((r) => r.key === "liquidity")?.status === "fulfilled"
      ? analysisBatch.results.find((r) => r.key === "liquidity").value
      : null;

  const related =
    analysisBatch.results.find((r) => r.key === "related")?.status === "fulfilled"
      ? analysisBatch.results.find((r) => r.key === "related").value
      : null;

  const correlated =
    analysisBatch.results.find((r) => r.key === "correlated")?.status === "fulfilled"
      ? analysisBatch.results.find((r) => r.key === "correlated").value
      : null;

  const primaryMarket = related?.primaryMarket || {};
  const siblingOutcomes = Array.isArray(related?.siblingOutcomes) ? related.siblingOutcomes : [];
  const correlatedMarkets = Array.isArray(correlated?.correlatedMarkets) ? correlated.correlatedMarkets : [];
